#!/bin/bash
set -e
cd "$(dirname "$0")"
python3 -c "import base64; open('scripts/daily-agent.mjs', 'wb').write(base64.b64decode(''))"
git add scripts/daily-agent.mjs
git commit -m "fix: update PROGRESS.md before git push so it gets committed"
git push origin main
echo "🚀 Push完了！"
echo ""
echo "=== PROGRESS.md を生成して確認 ==="
node scripts/daily-agent.mjs --dry-run
echo ""
echo "=== PROGRESS.md の内容 ==="
cat PROGRESS.md | head -60
